from celery import Celery
from celery.schedules import crontab
from kombu import Queue
import os

redis_url = os.getenv("REDIS_URL", "redis://localhost:6379/0")

celery_app = Celery(
    "bit_monitoring",
    broker=redis_url,
    backend=redis_url,
    include=[
        "workers.tasks.aws_monitor",
        "workers.tasks.zoom_monitor",
        "workers.tasks.uptime_monitor",
        "workers.tasks.docker_monitor",
        "workers.tasks.cost_sync",
        "workers.tasks.daily_aggregation",
        "workers.tasks.notifications",
        "workers.tasks.stripe_sync",
        "workers.tasks.zoom_sync",
        "workers.tasks.client_matching",
        "workers.tasks.push_notifications",
        "workers.tasks.infra_alert",
        "workers.tasks.diagnostic",
    ],
)

celery_app.conf.update(
    task_serializer="json",
    accept_content=["json"],
    result_serializer="json",
    timezone="UTC",
    enable_utc=True,
    task_track_started=True,
    task_time_limit=300,  # 5 minutes max per task
    worker_prefetch_multiplier=1,
    result_expires=3600,  # Results expire after 1 hour
)

# Queue isolation: monitor tasks run on a dedicated lightweight worker
# so heavy tasks (Stripe sync, CloudWatch polling) never block uptime checks
celery_app.conf.task_queues = [
    Queue("default"),
    Queue("monitors"),
]
celery_app.conf.task_default_queue = "default"
celery_app.conf.task_routes = {
    "workers.tasks.uptime_monitor.check_all_endpoints": {"queue": "monitors"},
    "workers.tasks.uptime_monitor.check_single_endpoint": {"queue": "monitors"},
    "workers.tasks.uptime_monitor.check_ssl_expiry": {"queue": "monitors"},
}

# Beat schedule for periodic tasks
celery_app.conf.beat_schedule = {
    # AWS resource discovery - every 15 minutes
    "discover-aws-resources": {
        "task": "workers.tasks.aws_monitor.discover_all_resources",
        "schedule": crontab(minute="*/15"),
    },
    # AWS metrics collection - every 5 minutes (staggered off :00 to avoid task pile-up)
    "collect-aws-metrics": {
        "task": "workers.tasks.aws_monitor.collect_all_metrics",
        "schedule": crontab(minute="1-59/5"),
    },
    # Zoom user discovery - every 15 minutes
    "discover-zoom-resources": {
        "task": "workers.tasks.zoom_monitor.discover_all_zoom_resources",
        "schedule": crontab(minute="*/15"),
    },
    # Uptime checks - every minute
    "check-uptime": {
        "task": "workers.tasks.uptime_monitor.check_all_endpoints",
        "schedule": crontab(minute="*"),
    },
    # Docker container checks - every 2 minutes
    "check-docker-hosts": {
        "task": "workers.tasks.docker_monitor.check_all_hosts",
        "schedule": crontab(minute="*/2"),
    },
    # SSL certificate expiry check - once daily at 6 AM UTC
    "check-ssl-expiry": {
        "task": "workers.tasks.uptime_monitor.check_ssl_expiry",
        "schedule": crontab(hour=6, minute=0),
    },
    # AWS cost sync - once daily at 6:30 AM UTC
    "sync-aws-costs": {
        "task": "workers.tasks.cost_sync.sync_all_costs",
        "schedule": crontab(hour=6, minute=30),
    },
    # Budget alert check - once daily at 7 AM UTC
    "check-budget-alerts": {
        "task": "workers.tasks.cost_sync.check_budget_alerts",
        "schedule": crontab(hour=7, minute=0),
    },
    # Daily uptime aggregation - once daily at 1 AM UTC (for yesterday's complete data)
    "aggregate-daily-uptime": {
        "task": "workers.tasks.daily_aggregation.aggregate_daily_uptime",
        "schedule": crontab(hour=1, minute=0),
    },
    # Update today's aggregates every 5 minutes (staggered off :00)
    "aggregate-today-uptime": {
        "task": "workers.tasks.daily_aggregation.aggregate_today_uptime",
        "schedule": crontab(minute="3-59/5"),
    },
    # Stripe sync - every hour (staggered off :00, heaviest task ~12s)
    "sync-stripe-accounts": {
        "task": "workers.tasks.stripe_sync.sync_all_stripe_accounts",
        "schedule": crontab(minute=5),
    },
    # Zoom user sync - every hour
    "sync-zoom-users": {
        "task": "workers.tasks.zoom_sync.sync_zoom_users_task",
        "schedule": crontab(minute=15),  # At 15 past every hour
    },
    # Client status update - every 30 minutes (staggered off :00 and :30)
    "update-client-statuses": {
        "task": "workers.tasks.client_matching.update_client_statuses_task",
        "schedule": crontab(minute="10,40"),
    },
    # Infrastructure metric alert evaluation - every 2 minutes
    "evaluate-infra-alerts": {
        "task": "workers.tasks.infra_alert.evaluate_infra_alerts",
        "schedule": crontab(minute="*/2"),
    },
    # OTel agent heartbeat check - every 5 minutes (staggered off :00)
    "check-agent-heartbeats": {
        "task": "workers.tasks.infra_alert.check_agent_heartbeats",
        "schedule": crontab(minute="2-59/5"),
    },
    # Expire stale diagnostic tasks - every 5 minutes (staggered off :00)
    "expire-stale-diagnostic-tasks": {
        "task": "workers.tasks.diagnostic.expire_stale_diagnostic_tasks",
        "schedule": crontab(minute="4-59/5"),
    },
}

import { useEffect, useRef, useState, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import { useQueryClient } from '@tanstack/react-query'
import { io, Socket } from 'socket.io-client'
import { useToast } from '@/components/Toast'

interface WebSocketEvent {
  incident_id: number
  title: string
  severity: string
  trigger_type: string
  resource_type?: string
  resource_id?: string
  status?: string
}

export function useWebSocket() {
  const { data: session, status: sessionStatus } = useSession()
  const queryClient = useQueryClient()
  const toast = useToast()
  const socketRef = useRef<Socket | null>(null)
  const [isConnected, setIsConnected] = useState(false)

  const invalidateNotificationQueries = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: ['notifications'] })
    queryClient.invalidateQueries({ queryKey: ['unreadCount'] })
  }, [queryClient])

  const invalidateIncidentQueries = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: ['incidents'] })
    queryClient.invalidateQueries({ queryKey: ['incidentSummary'] })
  }, [queryClient])

  useEffect(() => {
    if (sessionStatus !== 'authenticated' || !session?.accessToken) {
      return
    }

    // In production, Socket.IO goes through nginx (same origin).
    // In development (port 3000), Next.js rewrites don't support WebSocket
    // upgrades, so we connect directly to the backend on port 8000.
    const isDev = typeof window !== 'undefined' && window.location.port === '3000'
    const socketUrl = isDev
      ? `${window.location.protocol}//${window.location.hostname}:8000`
      : undefined  // undefined = same origin (through nginx)

    const socket = io(socketUrl, {
      path: '/socket.io/',
      auth: { token: session.accessToken },
      transports: ['polling', 'websocket'],
      reconnection: true,
      reconnectionAttempts: Infinity,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 30000,
    })

    socketRef.current = socket

    socket.on('connect', () => {
      setIsConnected(true)
    })

    socket.on('disconnect', () => {
      setIsConnected(false)
    })

    socket.on('connected', () => {
      // Server confirmed JWT authentication
    })

    socket.on('incident_created', (data: WebSocketEvent) => {
      invalidateIncidentQueries()
      invalidateNotificationQueries()

      const severityToast = data.severity === 'critical' ? 'error' : data.severity === 'warning' ? 'warning' : 'info'
      toast.showToast(severityToast, `New incident: ${data.title}`, 6000)
    })

    socket.on('incident_resolved', (data: WebSocketEvent) => {
      invalidateIncidentQueries()
      invalidateNotificationQueries()

      toast.success(`Resolved: ${data.title}`, 5000)
    })

    socket.on('incident_acknowledged', (data: WebSocketEvent) => {
      invalidateIncidentQueries()
      invalidateNotificationQueries()
    })

    socket.on('notification', () => {
      invalidateNotificationQueries()
    })

    socket.on('connect_error', () => {
      setIsConnected(false)
    })

    return () => {
      socket.disconnect()
      socketRef.current = null
      setIsConnected(false)
    }
  }, [session?.accessToken, sessionStatus, invalidateIncidentQueries, invalidateNotificationQueries, toast])

  return { isConnected }
}

'use client'

import { useSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'
import { useEffect } from 'react'
import Link from 'next/link'
import Sidebar from '@/components/Sidebar'
import OnboardingTour from '@/components/OnboardingTour'
import AgentCard from '@/components/AgentCard'
import { useResourceSummary } from '@/lib/hooks/useResources'
import { useCloudAccounts } from '@/lib/hooks/useCloudAccounts'
import { useUptimeMonitorSummary, useUptimeMonitors } from '@/lib/hooks/useUptimeMonitors'
import { useIncidentSummary, useIncidents, getSeverityColor, formatRelativeTime } from '@/lib/hooks/useIncidents'
import { useCostSummary, formatCurrency } from '@/lib/hooks/useCosts'
import { useInfraSummary, isAgentOnline } from '@/lib/hooks/useInfraMetrics'
import {
  Activity,
  AlertTriangle,
  Bell,
  CheckCircle,
  Cloud,
  Database,
  DollarSign,
  Globe,
  HardDrive,
  Server,
  XCircle,
} from 'lucide-react'

export default function Home() {
  const { data: session, status } = useSession()
  const router = useRouter()
  const { data: summary, isLoading: summaryLoading } = useResourceSummary()
  const { data: accounts, isLoading: accountsLoading } = useCloudAccounts()
  const { data: monitorSummary, isLoading: monitorsLoading } = useUptimeMonitorSummary()
  const { data: incidentSummary, isLoading: incidentsLoading } = useIncidentSummary()
  const { data: costSummary, isLoading: costsLoading } = useCostSummary()
  const { data: infraSummary, isLoading: infraLoading } = useInfraSummary()
  const { data: recentIncidentsData, isLoading: recentIncidentsLoading } = useIncidents({ page_size: 5 })
  const { data: downMonitors } = useUptimeMonitors({ status: 'down' })

  useEffect(() => {
    if (status === 'unauthenticated') {
      router.push('/login')
    }
  }, [status, router])

  if (status === 'loading') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-bit-bg-dark">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-bit-green"></div>
      </div>
    )
  }

  if (!session) {
    return null
  }

  const isAdmin = session.user.role === 'admin' || session.user.role === 'superadmin'

  const isLoading = summaryLoading || accountsLoading || monitorsLoading || incidentsLoading || costsLoading || infraLoading
  const totalResources = summary?.total_count || 0
  const ec2Count = summary?.by_type?.ec2 || 0
  const rdsCount = summary?.by_type?.rds || 0
  const runningCount = (summary?.by_status?.running || 0) + (summary?.by_status?.available || 0)
  const activeAccounts = accounts?.filter(a => a.is_active).length || 0

  // Monitors data
  const totalMonitors = monitorSummary?.total_monitors || 0
  const monitorsUp = monitorSummary?.up_count || 0
  const monitorsDown = monitorSummary?.down_count || 0

  // Incidents data
  const openIncidents = incidentSummary?.open || 0
  const acknowledgedIncidents = incidentSummary?.acknowledged || 0

  // Costs data
  const currentMonthCost = costSummary?.total_cost || 0

