"""IP enrichment service using ip-api.com with Redis cache.

ip-api.com free tier: 45 req/min.
Cache TTL: 7 days. Multi-worker safe (Redis, no SQLite lock contention).
"""
import json
import logging
import time
from typing import Optional

import httpx
import redis

from app.core.config import settings

logger = logging.getLogger(__name__)


class IpEnrichmentService:
    """Enrich IPs with geo/org info via ip-api.com. Redis cache 7 days."""

    CACHE_TTL = 7 * 86400  # 7 days
    RATE_LIMIT_BATCH = 9   # 9 IPs per batch
    RATE_LIMIT_SLEEP = 12  # 12s between batches → <45 req/min

    def __init__(self):
        self._redis = redis.from_url(settings.REDIS_URL, decode_responses=True)

    def enrich(self, ip: str) -> dict:
        """Enrich a single IP. Returns cached result if available."""
        if not ip:
            return {}
        cache_key = f"ip:enrichment:{ip}"
        cached = self._redis.get(cache_key)
        if cached:
            return json.loads(cached)
        try:
            resp = httpx.get(
                f"http://ip-api.com/json/{ip}",
                params={"fields": "country,countryCode,city,org,as,query"},
                timeout=3.0,
            )
            data = resp.json()
            self._redis.setex(cache_key, self.CACHE_TTL, json.dumps(data))
            return data
        except Exception as e:
            logger.warning(f"IP enrichment failed for {ip}: {e}")
            return {}

    def enrich_batch(self, ips: list[str]) -> dict[str, dict]:
        """Enrich multiple IPs, respecting rate limits.

        Skips IPs already cached. Batches remaining in groups of 9,
        sleeping 12s between batches to stay under 45 req/min.
        """
        results: dict[str, dict] = {}

        # Collect already-cached results
        new_ips = []
        for ip in ips:
            if not ip:
                continue
            cache_key = f"ip:enrichment:{ip}"
            cached = self._redis.get(cache_key)
            if cached:
                results[ip] = json.loads(cached)
            else:
                new_ips.append(ip)

        # Fetch uncached IPs in rate-limited batches
        for i in range(0, len(new_ips), self.RATE_LIMIT_BATCH):
            batch = new_ips[i:i + self.RATE_LIMIT_BATCH]
            for ip in batch:
                results[ip] = self.enrich(ip)
            if i + self.RATE_LIMIT_BATCH < len(new_ips):
                time.sleep(self.RATE_LIMIT_SLEEP)

        # Ensure all input IPs have an entry
        for ip in ips:
            if ip and ip not in results:
                results[ip] = self.enrich(ip)

        return results

