celery_app = Celery(
    "bit_monitoring",
    broker=redis_url,
    backend=redis_url,
    include=[
        "workers.tasks.aws_monitor",
        "workers.tasks.zoom_monitor",
        "workers.tasks.uptime_monitor",
        "workers.tasks.docker_monitor",
        "workers.tasks.cost_sync",
        "workers.tasks.daily_aggregation",
        "workers.tasks.notifications",
        "workers.tasks.stripe_sync",
        "workers.tasks.zoom_sync",
        "workers.tasks.client_matching",
        "workers.tasks.push_notifications",
        "workers.tasks.infra_alert",
        "workers.tasks.diagnostic",
        "workers.tasks.waf_collector",
    ],
)

celery_app.conf.update(
    task_serializer="json",
    accept_content=["json"],
    result_serializer="json",
    timezone="UTC",
    enable_utc=True,
    task_track_started=True,
    task_time_limit=300,  # 5 minutes max per task
    worker_prefetch_multiplier=1,
    result_expires=3600,  # Results expire after 1 hour
)

# Queue isolation: monitor tasks run on a dedicated lightweight worker
# so heavy tasks (Stripe sync, CloudWatch polling) never block uptime checks
celery_app.conf.task_queues = [
    Queue("default"),
    Queue("monitors"),
]
celery_app.conf.task_default_queue = "default"
celery_app.conf.task_routes = {
    "workers.tasks.uptime_monitor.check_all_endpoints": {"queue": "monitors"},
    "workers.tasks.uptime_monitor.check_single_endpoint": {"queue": "monitors"},
    "workers.tasks.uptime_monitor.check_ssl_expiry": {"queue": "monitors"},
}

# Beat schedule for periodic tasks
celery_app.conf.beat_schedule = {
    # AWS resource discovery - every 15 minutes
    "discover-aws-resources": {
        "task": "workers.tasks.aws_monitor.discover_all_resources",
        "schedule": crontab(minute="*/15"),
    },
    # AWS metrics collection - every 5 minutes (staggered off :00 to avoid task pile-up)
    "collect-aws-metrics": {
        "task": "workers.tasks.aws_monitor.collect_all_metrics",
        "schedule": crontab(minute="1-59/5"),
    },
    # Zoom user discovery - every 15 minutes
    "discover-zoom-resources": {
        "task": "workers.tasks.zoom_monitor.discover_all_zoom_resources",
        "schedule": crontab(minute="*/15"),
    },
    # Uptime checks - every minute
    "check-uptime": {
        "task": "workers.tasks.uptime_monitor.check_all_endpoints",
        "schedule": crontab(minute="*"),
    },
    # Docker container checks - every 2 minutes
    "check-docker-hosts": {
        "task": "workers.tasks.docker_monitor.check_all_hosts",
        "schedule": crontab(minute="*/2"),
    },
    # SSL certificate expiry check - once daily at 6 AM UTC
    "check-ssl-expiry": {
        "task": "workers.tasks.uptime_monitor.check_ssl_expiry",
        "schedule": crontab(hour=6, minute=0),
    },
    # AWS cost sync - once daily at 6:30 AM UTC
    "sync-aws-costs": {
        "task": "workers.tasks.cost_sync.sync_all_costs",
        "schedule": crontab(hour=6, minute=30),
    },
    # Budget alert check - once daily at 7 AM UTC
    "check-budget-alerts": {
        "task": "workers.tasks.cost_sync.check_budget_alerts",
        "schedule": crontab(hour=7, minute=0),
    },
    # Daily uptime aggregation - once daily at 1 AM UTC (for yesterday's complete data)
    "aggregate-daily-uptime": {
        "task": "workers.tasks.daily_aggregation.aggregate_daily_uptime",
        "schedule": crontab(hour=1, minute=0),
    },
    # Update today's aggregates every 5 minutes (staggered off :00)
    "aggregate-today-uptime": {
        "task": "workers.tasks.daily_aggregation.aggregate_today_uptime",
        "schedule": crontab(minute="3-59/5"),
    },
    # Stripe sync - every hour (staggered off :00, heaviest task ~12s)
    "sync-stripe-accounts": {
        "task": "workers.tasks.stripe_sync.sync_all_stripe_accounts",
        "schedule": crontab(minute=5),
    },
    # Zoom user sync - every hour
    "sync-zoom-users": {
        "task": "workers.tasks.zoom_sync.sync_zoom_users_task",
        "schedule": crontab(minute=15),  # At 15 past every hour
    },
    # Client status update - every 30 minutes (staggered off :00 and :30)
    "update-client-statuses": {
        "task": "workers.tasks.client_matching.update_client_statuses_task",
        "schedule": crontab(minute="10,40"),
    },
    # Infrastructure metric alert evaluation - every 2 minutes
    "evaluate-infra-alerts": {
        "task": "workers.tasks.infra_alert.evaluate_infra_alerts",
        "schedule": crontab(minute="*/2"),
    },
    # OTel agent heartbeat check - every 5 minutes (staggered off :00)
    "check-agent-heartbeats": {
        "task": "workers.tasks.infra_alert.check_agent_heartbeats",
        "schedule": crontab(minute="2-59/5"),
    },
    # Expire stale diagnostic tasks - every 5 minutes (staggered off :00)
    "expire-stale-diagnostic-tasks": {
        "task": "workers.tasks.diagnostic.expire_stale_diagnostic_tasks",
        "schedule": crontab(minute="4-59/5"),
    },
}

