import { useEffect, useRef, useState, useCallback } from 'react'
import { useSession } from 'next-auth/react'
import { useQueryClient } from '@tanstack/react-query'
import { io, Socket } from 'socket.io-client'
import { useToast } from '@/components/Toast'

interface WebSocketEvent {
  incident_id: number
  title: string
  severity: string
  trigger_type: string
  resource_type?: string
  resource_id?: string
  status?: string
}

export function useWebSocket() {
  const { data: session, status: sessionStatus } = useSession()
  const queryClient = useQueryClient()
  const toast = useToast()
  const socketRef = useRef<Socket | null>(null)
  const [isConnected, setIsConnected] = useState(false)

  const invalidateNotificationQueries = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: ['notifications'] })
    queryClient.invalidateQueries({ queryKey: ['unreadCount'] })
  }, [queryClient])

  const invalidateIncidentQueries = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: ['incidents'] })
    queryClient.invalidateQueries({ queryKey: ['incidentSummary'] })
  }, [queryClient])

  useEffect(() => {
    if (sessionStatus !== 'authenticated' || !session?.accessToken) {
      return
    }

    // In production, Socket.IO goes through nginx (same origin).
    // In development (port 3000), Next.js rewrites don't support WebSocket
    // upgrades, so we connect directly to the backend on port 8000.
    const isDev = typeof window !== 'undefined' && window.location.port === '3000'
    const socketUrl = isDev
      ? `${window.location.protocol}//${window.location.hostname}:8000`
      : undefined  // undefined = same origin (through nginx)

    const socket = io(socketUrl, {
      path: '/socket.io/',
      auth: { token: session.accessToken },
      transports: ['polling', 'websocket'],
      reconnection: true,
      reconnectionAttempts: Infinity,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 30000,
    })

    socketRef.current = socket

    socket.on('connect', () => {
      setIsConnected(true)
    })

    socket.on('disconnect', () => {
      setIsConnected(false)
    })

    socket.on('connected', () => {
      // Server confirmed JWT authentication
    })

    socket.on('incident_created', (data: WebSocketEvent) => {
      invalidateIncidentQueries()
      invalidateNotificationQueries()

      const severityToast = data.severity === 'critical' ? 'error' : data.severity === 'warning' ? 'warning' : 'info'
      toast.showToast(severityToast, `New incident: ${data.title}`, 6000)
    })

    socket.on('incident_resolved', (data: WebSocketEvent) => {
      invalidateIncidentQueries()
      invalidateNotificationQueries()

      toast.success(`Resolved: ${data.title}`, 5000)
    })

    socket.on('incident_acknowledged', (data: WebSocketEvent) => {
      invalidateIncidentQueries()
      invalidateNotificationQueries()
    })

    socket.on('notification', () => {
      invalidateNotificationQueries()
    })

    socket.on('connect_error', () => {
      setIsConnected(false)
    })

    return () => {
      socket.disconnect()
      socketRef.current = null
      setIsConnected(false)
    }
  }, [session?.accessToken, sessionStatus, invalidateIncidentQueries, invalidateNotificationQueries, toast])

  return { isConnected }
}

