/**
 * Data hooks for the Security Attack Monitoring module.
 * Uses TanStack Query + axios api client (project standard).
 */
import { useQuery } from '@tanstack/react-query'
import api from '@/lib/api'

export interface AttackSummary {
  period_hours: number
  total_blocks: number
  top_rules: { value: string; count: number }[]
  top_countries: { value: string; count: number }[]
  top_ips: { value: string; count: number }[]
  top_asns: { value: string; count: number }[]
  timeline: { hour: string; source: string; block_count: number }[]
  sources: { value: string; count: number }[]
}

export interface SecurityEvent {
  id: number
  timestamp: string
  source: string
  rule_name: string | null
  action: string
  country_code: string | null
  ip_address: string | null
  user_agent: string | null
  uri: string | null
  http_method: string | null
  status_code: number | null
  bot_category: string | null
  ip_org: string | null
  ip_city: string | null
  ip_asn: string | null
  threat_score: number | null
}

export interface SecurityEventsResponse {
  items: SecurityEvent[]
  total: number
  page: number
  page_size: number
}

export interface TopAttacker {
  ip: string
  org: string | null
  city: string | null
  asn: string | null
  country: string | null
  count: number
}

export function useAttackSummary(hours: number = 24) {
  return useQuery<AttackSummary>({
    queryKey: ['security', 'summary', hours],
    queryFn: () =>
      api.get(`/security/summary?hours=${hours}`).then((r) => r.data),
    refetchInterval: 30_000,
  })
}

export function useSecurityEvents(filters?: {
  hours?: number
  source?: string
  rule?: string
  page?: number
  page_size?: number
}) {
  return useQuery<SecurityEventsResponse>({
    queryKey: ['security', 'events', filters],
    queryFn: () =>
      api.get('/security/events', { params: filters }).then((r) => r.data),
    refetchInterval: 30_000,
  })
}

export function useAttackTimeline(hours: number = 24) {
  return useQuery<{ hour: string; source: string; block_count: number }[]>({
    queryKey: ['security', 'timeline', hours],
    queryFn: () =>
      api.get(`/security/timeline?hours=${hours}`).then((r) => r.data),
    refetchInterval: 60_000,
  })
}

export function useTopAttackers(hours: number = 24, limit: number = 20) {
  return useQuery<TopAttacker[]>({
    queryKey: ['security', 'top-attackers', hours, limit],
    queryFn: () =>
      api
        .get(`/security/top-attackers?hours=${hours}&limit=${limit}`)
        .then((r) => r.data),
    refetchInterval: 60_000,
  })
}

