'use client'

import { Shield, AlertTriangle, Globe, Activity } from 'lucide-react'
import type { AttackSummary } from '@/lib/hooks/useSecurityEvents'

interface Props {
  summary: AttackSummary | undefined
  isLoading: boolean
}

export default function AttackKpiCards({ summary, isLoading }: Props) {
  const val = (v: number | undefined) => (isLoading ? '--' : String(v ?? 0))

  const topCountry = summary?.top_countries?.[0]?.value ?? '—'
  const topRule = summary?.top_rules?.[0]?.value ?? '—'
  const cfBlocks =
    summary?.sources?.find((s) => s.value === 'waf_cloudfront')?.count ?? 0
  const albBlocks =
    summary?.sources?.find((s) => s.value === 'waf_alb')?.count ?? 0

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-6">
      <KpiCard
        icon={<Shield className="h-6 w-6 text-bit-red" />}
        title="Total Bloqueios"
        value={val(summary?.total_blocks)}
        subtitle={`Últimas ${summary?.period_hours ?? 24}h`}
      />
      <KpiCard
        icon={<Activity className="h-6 w-6 text-bit-orange" />}
        title="CloudFront WAF"
        value={isLoading ? '--' : String(cfBlocks)}
        subtitle="Bloqueios CDN"
      />
      <KpiCard
        icon={<Activity className="h-6 w-6 text-bit-yellow" />}
        title="ALB WAF"
        value={isLoading ? '--' : String(albBlocks)}
        subtitle="Bloqueios ALB"
      />
      <KpiCard
        icon={<Globe className="h-6 w-6 text-bit-cyan" />}
        title="País Principal"
        value={isLoading ? '--' : topCountry}
        subtitle={`Regra: ${topRule.slice(0, 20)}`}
      />
    </div>
  )
}

function KpiCard({
  icon,
  title,
  value,
  subtitle,
}: {
  icon: React.ReactNode
  title: string
  value: string
  subtitle: string
}) {
  return (
    <div className="bg-bit-bg rounded-lg border border-bit-border p-6">
      <div className="flex items-center justify-between mb-2">
        <span className="text-sm text-bit-muted">{title}</span>
        {icon}
      </div>
      <div className="text-2xl font-bold text-bit-text">{value}</div>
      <div className="text-xs text-bit-muted mt-1 truncate">{subtitle}</div>
    </div>
  )
}

