'use client'

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts'

interface TimelineRow {
  hour: string
  source: string
  block_count: number
}

interface Props {
  data: TimelineRow[] | undefined
  isLoading: boolean
}

export default function AttackTimeline({ data, isLoading }: Props) {
  if (isLoading) {
    return (
      <div className="bg-bit-bg rounded-lg border border-bit-border p-6 mb-6">
        <h2 className="text-lg font-medium text-bit-text mb-4">Timeline de Ataques</h2>
        <div className="h-48 flex items-center justify-center">
          <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-bit-green" />
        </div>
      </div>
    )
  }

  // Pivot: group by hour, columns = sources
  const byHour: Record<string, Record<string, number>> = {}
  for (const row of data ?? []) {
    const h = row.hour.slice(0, 13) // "2026-03-20T14"
    if (!byHour[h]) byHour[h] = {}
    byHour[h][row.source] = (byHour[h][row.source] ?? 0) + row.block_count
  }
  const chartData = Object.entries(byHour)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([hour, counts]) => ({ hour: hour.slice(-5), ...counts }))

  return (
    <div className="bg-bit-bg rounded-lg border border-bit-border p-6 mb-6">
      <h2 className="text-lg font-medium text-bit-text mb-4">Timeline de Ataques (por hora)</h2>
      {chartData.length === 0 ? (
        <p className="text-bit-muted text-sm">Nenhum dado disponível.</p>
      ) : (
        <ResponsiveContainer width="100%" height={220}>
          <BarChart data={chartData}>
            <XAxis dataKey="hour" tick={{ fill: '#9ca3af', fontSize: 11 }} />
            <YAxis tick={{ fill: '#9ca3af', fontSize: 11 }} />
            <Tooltip
              contentStyle={{ background: '#1e1e2e', border: '1px solid #334155', color: '#e2e8f0' }}
            />
            <Legend />
            <Bar dataKey="waf_cloudfront" name="CloudFront WAF" fill="#f97316" stackId="a" />
            <Bar dataKey="waf_alb" name="ALB WAF" fill="#3b82f6" stackId="a" />
          </BarChart>
        </ResponsiveContainer>
      )}
    </div>
  )
}

