'use client'

import { useState, useEffect } from 'react'
import { useSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'
import { Shield, RefreshCw } from 'lucide-react'
import Sidebar from '@/components/Sidebar'
import {
  useAttackSummary,
  useAttackTimeline,
  useTopAttackers,
} from '@/lib/hooks/useSecurityEvents'
import AttackKpiCards from './components/AttackKpiCards'
import AttackTimeline from './components/AttackTimeline'
import TopAttackersTable from './components/TopAttackersTable'
import AttackRulesBreakdown from './components/AttackRulesBreakdown'
import RecentEventsTable from './components/RecentEventsTable'

const PERIOD_OPTIONS = [
  { label: '1h', value: 1 },
  { label: '6h', value: 6 },
  { label: '24h', value: 24 },
  { label: '7d', value: 168 },
  { label: '30d', value: 720 },
]

export default function SecurityPage() {
  const { data: session, status } = useSession()
  const router = useRouter()
  const [hours, setHours] = useState(24)

  useEffect(() => {
    if (status === 'unauthenticated') {
      router.push('/login')
    }
  }, [status, router])

  const { data: summary, isLoading: summaryLoading, refetch: refetchSummary } = useAttackSummary(hours)
  const { data: timeline, isLoading: timelineLoading } = useAttackTimeline(hours)
  const { data: topAttackers, isLoading: attackersLoading } = useTopAttackers(hours, 20)

  if (status === 'loading') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-bit-bg-dark">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-bit-green" />
      </div>
    )
  }

  if (!session) return null

  return (
    <div className="flex min-h-screen bg-bit-bg-dark">
      <Sidebar />

      <div className="flex-1 p-4 md:p-8 pt-20 md:pt-20 lg:pt-8">
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <Shield className="h-6 w-6 text-bit-red" />
            <div>
              <h1 className="text-2xl font-gotham text-bit-text">Monitoramento de Ataques</h1>
              <p className="text-bit-muted text-sm">
                WAF CloudFront + ALB — concertacaoamazonia.com.br
              </p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            {/* Period selector */}
            <div className="flex border border-bit-border rounded-md overflow-hidden">
              {PERIOD_OPTIONS.map((opt) => (
                <button
                  key={opt.value}
                  onClick={() => setHours(opt.value)}
                  className={`px-3 py-1.5 text-xs font-medium transition-colors ${
                    hours === opt.value
                      ? 'bg-bit-red text-white'
                      : 'text-bit-muted hover:text-bit-text hover:bg-bit-border'
                  }`}
                >
                  {opt.label}
                </button>
              ))}
            </div>

            <button
              onClick={() => refetchSummary()}
              className="p-2 border border-bit-border rounded-md text-bit-muted hover:text-bit-text hover:bg-bit-border transition-colors"
              title="Atualizar"
            >
              <RefreshCw className="h-4 w-4" />
            </button>
          </div>
        </div>

        {/* KPI Cards */}
        <AttackKpiCards summary={summary} isLoading={summaryLoading} />

        {/* Timeline */}
        <AttackTimeline data={timeline} isLoading={timelineLoading} />

        {/* Rules breakdown + Top attackers (2-column) */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
          <AttackRulesBreakdown summary={summary} isLoading={summaryLoading} />
          <TopAttackersTable data={topAttackers} isLoading={attackersLoading} />
        </div>

        {/* Recent events */}
        <RecentEventsTable hours={hours} />
      </div>
    </div>
  )
}

