'use client'

import { useState, useEffect } from 'react'
import { useSecurityEvents } from '@/lib/hooks/useSecurityEvents'

interface Props {
  hours: number
}

export default function RecentEventsTable({ hours }: Props) {
  const [page, setPage] = useState(1)

  // Reset to page 1 when the period changes to avoid showing empty pages
  useEffect(() => {
    setPage(1)
  }, [hours])

  const { data, isLoading } = useSecurityEvents({ hours, page, page_size: 50 })

  const events = data?.items ?? []
  const total = data?.total ?? 0
  const totalPages = Math.ceil(total / 50)

  return (
    <div className="bg-bit-bg rounded-lg border border-bit-border p-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-lg font-medium text-bit-text">
          Eventos Recentes
          {total > 0 && (
            <span className="ml-2 text-sm text-bit-muted">({total.toLocaleString()} total)</span>
          )}
        </h2>
        <div className="flex gap-2">
          <button
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            disabled={page <= 1}
            className="px-2 py-1 text-xs border border-bit-border rounded disabled:opacity-40 text-bit-muted hover:text-bit-text"
          >
            ←
          </button>
          <span className="text-xs text-bit-muted py-1">p.{page}</span>
          <button
            onClick={() => setPage((p) => p + 1)}
            disabled={events.length < 50}
            className="px-2 py-1 text-xs border border-bit-border rounded disabled:opacity-40 text-bit-muted hover:text-bit-text"
          >
            →
          </button>
        </div>
      </div>

      {isLoading ? (
        <div className="h-32 flex items-center justify-center">
          <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-bit-green" />
        </div>
      ) : events.length === 0 ? (
        <p className="text-bit-muted text-sm">Nenhum evento encontrado.</p>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full text-xs text-bit-text">
            <thead>
              <tr className="text-bit-muted border-b border-bit-border">
                <th className="text-left py-2 pr-3">Timestamp</th>
                <th className="text-left py-2 pr-3">Source</th>
                <th className="text-left py-2 pr-3">IP</th>
                <th className="text-left py-2 pr-3">País</th>
                <th className="text-left py-2 pr-3">Regra</th>
                <th className="text-left py-2">URI</th>
              </tr>
            </thead>
            <tbody>
              {events.map((e) => (
                <tr key={e.id} className="border-b border-bit-border hover:bg-bit-bg-dark">
                  <td className="py-1.5 pr-3 font-mono text-bit-muted whitespace-nowrap">
                    {new Date(e.timestamp).toLocaleString('pt-BR')}
                  </td>
                  <td className="py-1.5 pr-3">
                    <span
                      className={`px-1.5 py-0.5 rounded text-xs ${
                        e.source === 'waf_cloudfront'
                          ? 'bg-orange-900/40 text-orange-300'
                          : 'bg-blue-900/40 text-blue-300'
                      }`}
                    >
                      {e.source === 'waf_cloudfront' ? 'CF' : 'ALB'}
                    </span>
                  </td>
                  <td className="py-1.5 pr-3 font-mono text-bit-cyan">{e.ip_address ?? '—'}</td>
                  <td className="py-1.5 pr-3">{e.country_code ?? '—'}</td>
                  <td className="py-1.5 pr-3 max-w-[160px] truncate text-bit-muted">
                    {e.rule_name ?? '—'}
                  </td>
                  <td className="py-1.5 max-w-[200px] truncate text-bit-muted">{e.uri ?? '—'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  )
}

